import{_ as t,o as a,c as d,au as r}from"./chunks/framework.DjOerXpq.js";const b=JSON.parse('{"title":"Service","description":"Feathers service for background task execution","frontmatter":{"title":"Service","description":"Feathers service for background task execution"},"headers":[],"relativePath":"packages/feathers-tasks/API/service.md","filePath":"packages/feathers-tasks/API/service.md"}'),o={name:"packages/feathers-tasks/API/service.md"};function s(c,e,i,n,h,l){return a(),d("div",null,[...e[0]||(e[0]=[r('<h1 id="service" tabindex="-1">Service <a class="header-anchor" href="#service" aria-label="Permalink to &quot;Service&quot;">​</a></h1><h2 id="featherstasks-options" tabindex="-1">feathersTasks (options) <a class="header-anchor" href="#featherstasks-options" aria-label="Permalink to &quot;feathersTasks (options)&quot;">​</a></h2><p>Configures and registers the <code>tasks</code> service on a Feathers application. Called via <code>app.configure()</code>.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th><th>Required</th></tr></thead><tbody><tr><td><code>persistenceService</code></td><td>Name of the Feathers service used to persist task records.</td><td>yes</td></tr><tr><td><code>redis</code></td><td>Redis connection options passed directly to BullMQ (<code>{ host, port, password, ... }</code>).</td><td>yes</td></tr><tr><td><code>queue.name</code></td><td>BullMQ queue name. Default: <code>&#39;tasks&#39;</code>.</td><td>no</td></tr><tr><td><code>queue.concurrency</code></td><td>Number of jobs processed in parallel by the worker. Default: <code>1</code>.</td><td>no</td></tr><tr><td><code>handlers</code></td><td>Object mapping job type names to async handler functions <code>(job) =&gt; any</code>.</td><td>no</td></tr><tr><td><code>dashboard.enabled</code></td><td>Mount the Bull Board UI. Default: <code>false</code>.</td><td>no</td></tr><tr><td><code>dashboard.basePath</code></td><td>Base path for the Bull Board Express router. Default: <code>&#39;/admin/tasks&#39;</code>.</td><td>no</td></tr></tbody></table><p>Registers <code>app.service(&#39;tasks&#39;)</code> as a <code>TaskService</code> instance.</p><h2 id="taskservice" tabindex="-1">TaskService <a class="header-anchor" href="#taskservice" aria-label="Permalink to &quot;TaskService&quot;">​</a></h2><h3 id="create-data-params" tabindex="-1">create (data, params) <a class="header-anchor" href="#create-data-params" aria-label="Permalink to &quot;create (data, params)&quot;">​</a></h3><p>Submits a new task to the BullMQ queue and creates a record in the persistence service.</p><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>data.type</code></td><td>string</td><td>yes</td><td>Job type — matched against a key in <code>handlers</code>.</td></tr><tr><td><code>data.payload</code></td><td>object</td><td>no</td><td>Arbitrary data forwarded to the handler as <code>job.data</code>.</td></tr><tr><td><code>data.options</code></td><td>object</td><td>no</td><td>BullMQ <a href="https://api.docs.bullmq.io/types/v5.JobsOptions.html" target="_blank" rel="noreferrer">JobsOptions</a> (delay, attempts, priority, etc.).</td></tr></tbody></table><p>Returns the persisted task record:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td>BullMQ job id.</td></tr><tr><td><code>type</code></td><td>Job type.</td></tr><tr><td><code>payload</code></td><td>Data passed to the handler.</td></tr><tr><td><code>status</code></td><td><code>&#39;waiting&#39;</code> at creation time.</td></tr><tr><td><code>createdAt</code></td><td>ISO timestamp.</td></tr></tbody></table><h3 id="find-params" tabindex="-1">find (params) <a class="header-anchor" href="#find-params" aria-label="Permalink to &quot;find (params)&quot;">​</a></h3><p>Delegates to the persistence service. Accepts the same <code>params.query</code> as the underlying adapter.</p><p>Returns a list (or paginated result) of task records.</p><h3 id="get-id-params" tabindex="-1">get (id, params) <a class="header-anchor" href="#get-id-params" aria-label="Permalink to &quot;get (id, params)&quot;">​</a></h3><p>Retrieves a single task record from the persistence service by BullMQ job <code>id</code>.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td>BullMQ job id (string).</td></tr></tbody></table><p>Throws <code>NotFound</code> if no record matches.</p><h3 id="patch-id-data-params" tabindex="-1">patch (id, data, params) <a class="header-anchor" href="#patch-id-data-params" aria-label="Permalink to &quot;patch (id, data, params)&quot;">​</a></h3><p>Updates fields on a task record in the persistence service. Primarily used internally by the <code>QueueEvents</code> listener to reflect status changes.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td>BullMQ job id.</td></tr><tr><td><code>data</code></td><td>Fields to merge into the record (e.g. <code>{ status, completedAt, result }</code>).</td></tr></tbody></table><h3 id="remove-id-params" tabindex="-1">remove (id, params) <a class="header-anchor" href="#remove-id-params" aria-label="Permalink to &quot;remove (id, params)&quot;">​</a></h3><p>Cancels the BullMQ job (if still pending) and removes the record from the persistence service.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td>BullMQ job id.</td></tr></tbody></table><p>Throws <code>NotFound</code> if no persistence record matches. Does not throw if the job is no longer in the queue (already completed/failed).</p>',25)])])}const u=t(o,[["render",s]]);export{b as __pageData,u as default};
